class Solution:
    def findLengthOfLCIS(self, nums):
        best = 0
        n = len(nums)
        for i in range(n):
            j = i
            while j + 1 < n and nums[j + 1] > nums[j]:
                j += 1
            best = max(best, j - i + 1)
        return best

