class Solution:
    def findLengthOfLCIS(self, nums):
        best = cur = 1
        for i in range(1, len(nums)):
            if nums[i] > nums[i - 1]:
                cur += 1
            else:
                cur = 1
            if cur > best:
                best = cur
        return best

